    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 breaking change: default renderer changed from Professional to System.
        // Restore .NET 8 appearance by explicitly setting the professional renderer.
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        Controls.Add(_statusStrip);
    }
}

public class MyDropDownEditor : UITypeEditor
{
    public override object? EditValue(
        System.ComponentModel.ITypeDescriptorContext? context,
        IServiceProvider provider,
        object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;

        if (editorService is null)
            return value;

        // .NET 9 breaking change: DropDownControl(null) now throws ArgumentNullException.
        // Guard against null control before calling.
        var control = CreateDropDownControl(value);
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = GetValueFromControl(control);
        }

        return value;
    }

    private Control? CreateDropDownControl(object? currentValue) => new ListBox();
    private object? GetValueFromControl(Control control) => ((ListBox)control).SelectedItem;
}

